import type { QAItem } from '../interview-data'

export const JS_TS_DATA: QAItem[] = [
  // === JavaScript: Kiểu Dữ Liệu & Biến (201-210) ===
  { id: 201, category: "JavaScript", subcategory: "Kiểu Dữ Liệu & Biến", level: "beginner", q: "Sự khác biệt giữa var, let và const là gì?", a: "var: function scope, hoisting (giá trị undefined), có thể khai báo lại — dễ gây bug, tránh dùng. let: block scope, Temporal Dead Zone (TDZ — không truy cập trước khai báo), có thể gán lại. const: block scope, TDZ, KHÔNG gán lại — nhưng object/array bên trong vẫn mutable. Best practice: mặc định dùng const, chỉ let khi cần reassign, không bao giờ dùng var." },
  { id: 202, category: "JavaScript", subcategory: "Kiểu Dữ Liệu & Biến", level: "beginner", q: "JavaScript có những kiểu dữ liệu nguyên thủy (primitive types) nào?", a: "JavaScript có 7 kiểu nguyên thủy: string, number, boolean, null, undefined, Symbol (ES6) và BigInt (ES2020). Các kiểu này được lưu theo giá trị (value), không phải tham chiếu (reference). Ví dụ: `let a = 5; let b = a; b = 10;` thì a vẫn là 5 vì number là primitive. Khác với object và array là reference types — nếu sửa object qua biến b, biến a cũng bị ảnh hưởng. Mẹo phỏng vấn: typeof null trả về 'object' là bug lịch sử, không phải null là object." },
  { id: 203, category: "JavaScript", subcategory: "Kiểu Dữ Liệu & Biến", level: "beginner", q: "Tại sao typeof null trả về 'object'?", a: "Đây là bug lịch sử từ JavaScript 1.0 (1995). Trong thiết kế ban đầu, các giá trị được biểu diễn bằng type tag + value: objects có tag 0, và null là con trỏ null (0x00) nên cũng có tag 0, bị nhầm là object. Bug này không được sửa để tránh phá vỡ hàng triệu dòng code cũ trên web. Cách kiểm tra null đúng: dùng `=== null` thay vì typeof. Đây là câu hỏi phỏng vấn kinh điển để test kiến thức về quirks của JS." },
  { id: 204, category: "JavaScript", subcategory: "Kiểu Dữ Liệu & Biến", level: "beginner", q: "Sự khác biệt giữa undefined và null là gì?", a: "undefined là giá trị mặc định khi biến được khai báo nhưng chưa gán giá trị. null là giá trị do lập trình viên chủ động gán để biểu thị 'không có giá trị'. undefined === undefined là true, nhưng null == undefined là true còn null === undefined là false." },
  { id: 205, category: "JavaScript", subcategory: "Kiểu Dữ Liệu & Biến", level: "intermediate", q: "Symbol trong JavaScript là gì và dùng để làm gì?", a: "Symbol là kiểu dữ liệu nguyên thủy tạo ra giá trị duy nhất (unique). Mỗi Symbol() tạo ra một giá trị không bao giờ bằng nhau dù có cùng description. Symbol thường dùng làm key cho object property để tránh xung đột tên, hoặc tạo các well-known symbols như Symbol.iterator." },
  { id: 206, category: "JavaScript", subcategory: "Kiểu Dữ Liệu & Biến", level: "intermediate", q: "BigInt trong JavaScript là gì? Khi nào nên dùng?", a: "BigInt là kiểu dữ liệu cho phép biểu diễn số nguyên lớn hơn Number.MAX_SAFE_INTEGER (2^53 - 1). Khai báo bằng cách thêm n sau số (ví dụ: 9007199254740993n) hoặc dùng BigInt(). Dùng khi cần tính toán với số nguyên rất lớn như ID database 64-bit hay mật mã học." },
  { id: 207, category: "JavaScript", subcategory: "Kiểu Dữ Liệu & Biến", level: "beginner", q: "Toán tử == và === khác nhau như thế nào?", a: "== là so sánh lỏng (loose equality), tự động chuyển đổi kiểu (type coercion) trước khi so sánh. === là so sánh chặt (strict equality), kiểm tra cả giá trị lẫn kiểu dữ liệu. Luôn nên dùng === để tránh những kết quả không mong muốn như 0 == '0' là true." },
  { id: 208, category: "JavaScript", subcategory: "Kiểu Dữ Liệu & Biến", level: "beginner", q: "Type coercion (ép kiểu tự động) trong JavaScript là gì?", a: "Type coercion là quá trình JavaScript tự động chuyển đổi kiểu dữ liệu khi thực hiện phép tính. Với `+`, nếu có string thì ưu tiên nối chuỗi: `'5' + 3 = '53'`. Với `-`, `*`, `/` thì ép về number: `'5' - 3 = 2`. Bẫy nổi tiếng: `[] + [] = ''`, `[] + {} = '[object Object]'`. Cách phòng: luôn dùng `===` thay `==`, dùng `Number()`, `String()`, `Boolean()` để ép kiểu tường minh thay để JS tự làm." },
  { id: 209, category: "JavaScript", subcategory: "Kiểu Dữ Liệu & Biến", level: "beginner", q: "Truthy và falsy values trong JavaScript là gì?", a: "Falsy values là các giá trị bị chuyển thành false trong ngữ cảnh boolean, gồm đúng 8 giá trị: false, 0, -0, 0n, '', null, undefined, NaN. Tất cả giá trị còn lại đều truthy — kể cả những giá trị dễ nhầm như '0' (string), [] (mảng rỗng), {} (object rỗng). Bẫy phổ biến: `if (arr.length)` hoạt động vì 0 là falsy, nhưng `if (obj)` luôn true dù obj là object rỗng. Dùng `Boolean(val)` hoặc `!!val` để chuyển về boolean tường minh." },
  { id: 210, category: "JavaScript", subcategory: "Kiểu Dữ Liệu & Biến", level: "intermediate", q: "NaN là gì? Tại sao NaN !== NaN?", a: "NaN (Not a Number) là giá trị đặc biệt xuất hiện khi phép tính số học thất bại: `parseInt('abc')`, `0/0`, `Math.sqrt(-1)`. Theo chuẩn IEEE 754, NaN không bằng bất kỳ giá trị nào kể cả chính nó — `NaN === NaN` là false. Dùng `Number.isNaN(val)` để kiểm tra chính xác (không dùng `isNaN()` vì hàm global này ép kiểu trước: `isNaN('hello')` trả về true). Bẫy: `typeof NaN` trả về `'number'` — NaN vẫn là kiểu number, chỉ là giá trị không hợp lệ." },

  // === JavaScript: Hoisting & Closure (211-225) ===
  { id: 211, category: "JavaScript", subcategory: "Hoisting & Closure", level: "beginner", q: "Hoisting trong JavaScript là gì?", a: "Hoisting là cơ chế JavaScript đưa khai báo biến và hàm lên đầu phạm vi (scope) trước khi thực thi. var được hoisted và khởi tạo với undefined, function declaration được hoisted hoàn toàn. let và const được hoisted nhưng không khởi tạo, tạo ra Temporal Dead Zone." },
  { id: 212, category: "JavaScript", subcategory: "Hoisting & Closure", level: "intermediate", q: "Temporal Dead Zone (TDZ) là gì?", a: "TDZ là khoảng thời gian từ khi block bắt đầu đến khi biến let/const được khai báo. Trong TDZ, việc truy cập biến sẽ ném ReferenceError dù biến đã được hoisted. Ví dụ: `console.log(x); let x = 5;` sẽ throw ReferenceError, trong khi var chỉ trả về undefined. TDZ giúp phát hiện lỗi dùng biến trước khi khai báo — điều var cho phép nhưng gây bug khó tìm. Khi phỏng vấn hỏi về TDZ, nhớ nêu rằng biến vẫn được hoisted nhưng chưa được khởi tạo." },
  { id: 213, category: "JavaScript", subcategory: "Hoisting & Closure", level: "intermediate", q: "Scope chain trong JavaScript hoạt động như thế nào?", a: "Scope chain là cơ chế JavaScript tìm kiếm biến từ scope hiện tại ra ngoài đến global scope. Khi không tìm thấy biến trong scope hiện tại, JS tìm trong scope cha, rồi tiếp tục lên cho đến global. Nếu không tìm thấy ở global, ném ReferenceError." },
  { id: 214, category: "JavaScript", subcategory: "Hoisting & Closure", level: "intermediate", q: "Closure là gì? Cho ví dụ thực tế.", a: "Closure là hàm 'nhớ' được biến từ lexical scope bên ngoài, ngay cả sau khi hàm ngoài đã return. Ví dụ: `function makeCounter() { let count = 0; return () => ++count; } const c = makeCounter(); c(); // 1, c(); // 2` — hàm trả về vẫn truy cập `count`. Ứng dụng thực tế: private variables (encapsulation), factory functions, event handlers giữ state, debounce/throttle, React hooks (useState bên trong dùng closure)." },
  { id: 215, category: "JavaScript", subcategory: "Hoisting & Closure", level: "intermediate", q: "Lexical scope là gì?", a: "Lexical scope (static scope) nghĩa là phạm vi của biến được xác định tại thời điểm viết code, không phải lúc chạy. Hàm con có thể truy cập biến của hàm cha nơi nó được định nghĩa, không phải nơi nó được gọi. Đây là nền tảng của closure trong JavaScript." },
  { id: 216, category: "JavaScript", subcategory: "Hoisting & Closure", level: "advanced", q: "Closure có thể gây memory leak như thế nào?", a: "Closure giữ tham chiếu đến scope ngoài, ngăn garbage collector giải phóng bộ nhớ. Vấn đề xảy ra khi closure không cần thiết giữ tham chiếu đến đối tượng lớn hoặc DOM node đã bị xóa. Cách phòng tránh: xóa event listeners không dùng, null hóa tham chiếu, tránh closures trong vòng lặp không cần thiết." },
  { id: 217, category: "JavaScript", subcategory: "Hoisting & Closure", level: "advanced", q: "Module pattern sử dụng closure như thế nào?", a: "Module pattern dùng IIFE và closure để tạo private state. Hàm bên trong có thể truy cập biến private của IIFE nhưng code bên ngoài không thể. Pattern này cho phép encapsulation trước khi ES modules được giới thiệu, tạo API public qua returned object." },
  { id: 218, category: "JavaScript", subcategory: "Hoisting & Closure", level: "beginner", q: "Sự khác biệt giữa function scope và block scope là gì?", a: "Function scope: biến khai báo bằng `var` chỉ tồn tại trong hàm chứa nó, mọi block `{}` bên trong đều dùng chung. Block scope: biến `let`/`const` chỉ tồn tại trong khối `{}` gần nhất — if, for, while, hay bất kỳ `{}` nào. Ví dụ rò rỉ var: `for (var i = 0; i < 3; i++) {}; console.log(i)` in ra 3 vì i thoát ra ngoài for. Với `let`, biến i không tồn tại ngoài vòng lặp. Đây là lý do chính để tránh dùng var trong code hiện đại." },
  { id: 219, category: "JavaScript", subcategory: "Hoisting & Closure", level: "intermediate", q: "Vấn đề classic về closure trong vòng lặp with var là gì?", a: "Khi dùng `var` trong vòng lặp for, tất cả callback chia sẻ cùng tham chiếu đến biến i — vì var là function scope, chỉ có một biến i duy nhất. Ví dụ: `for (var i = 0; i < 3; i++) { setTimeout(() => console.log(i), 0); }` in ra `3 3 3` thay vì `0 1 2`. Giải pháp đơn giản nhất: thay `var` bằng `let` — block scope tạo ra một biến i riêng cho mỗi iteration. Giải pháp cũ hơn: dùng IIFE `(function(j) { setTimeout(() => console.log(j), 0); })(i)` để capture giá trị. Đây là câu hỏi phỏng vấn cổ điển về closure." },
  { id: 220, category: "JavaScript", subcategory: "Hoisting & Closure", level: "intermediate", q: "Sự khác biệt giữa function declaration và function expression trong hoisting là gì?", a: "Function declaration được hoisted hoàn toàn (cả tên và thân hàm), có thể gọi trước khi khai báo. Function expression chỉ hoisted phần khai báo biến (với var là undefined), không thể gọi trước khi gán. Điều này ảnh hưởng đến thứ tự khai báo trong code." },
  { id: 221, category: "JavaScript", subcategory: "Hoisting & Closure", level: "advanced", q: "Garbage collection trong JavaScript hoạt động như thế nào liên quan đến closure?", a: "JavaScript dùng mark-and-sweep algorithm: đánh dấu tất cả đối tượng có thể truy cập từ root (global), sau đó dọn dẹp những gì không được đánh dấu. Closure ngăn GC vì giữ reference đến outer scope. V8 engine tối ưu bằng cách chỉ giữ những biến thực sự được dùng trong closure." },
  { id: 222, category: "JavaScript", subcategory: "Hoisting & Closure", level: "intermediate", q: "Partial application và closure liên quan với nhau như thế nào?", a: "Partial application tạo hàm mới bằng cách cố định một số argument của hàm gốc, nhờ closure để nhớ các argument đó. Ví dụ: `const multiply = (a, b) => a * b; const double = (b) => multiply(2, b);` — double dùng closure để nhớ a=2. Khác currying ở chỗ partial application cố định nhiều argument cùng lúc. Hữu ích khi cần tạo hàm chuyên biệt từ hàm chung, ví dụ tạo logger với prefix cố định hay validator với rules cố định." },
  { id: 223, category: "JavaScript", subcategory: "Hoisting & Closure", level: "advanced", q: "Tại sao var trong global scope tạo property trên window object?", a: "Trong browser, var khai báo ở global scope được thêm vào window object vì global execution context gắn với window. let và const ở global scope không thêm vào window, chúng nằm trong script scope riêng biệt. Đây là lý do tránh dùng var ở global scope." },
  { id: 224, category: "JavaScript", subcategory: "Hoisting & Closure", level: "intermediate", q: "Closures có ảnh hưởng đến performance không?", a: "Closure có overhead nhỏ về bộ nhớ vì phải lưu trữ tham chiếu đến outer scope. Tuy nhiên, V8 engine tối ưu tốt và overhead thường không đáng kể trong thực tế. Vấn đề chỉ xuất hiện khi tạo hàng nghìn closure giữ reference đến đối tượng lớn." },
  { id: 225, category: "JavaScript", subcategory: "Hoisting & Closure", level: "advanced", q: "Stale closure là gì và cách phòng tránh?", a: "Stale closure xảy ra khi closure nắm giữ giá trị cũ của biến thay vì giá trị mới nhất. Thường gặp trong React hooks khi useEffect capture state cũ. Cách phòng: thêm dependency vào dependency array, dùng useRef để lưu giá trị mới nhất, hoặc dùng functional update trong setState." },

  // === JavaScript: Functions (226-240) ===
  { id: 226, category: "JavaScript", subcategory: "Functions", level: "beginner", q: "Sự khác biệt giữa function declaration, function expression và arrow function là gì?", a: "Function declaration: hoisted hoàn toàn, có tên trong stack trace. Function expression: gán vào biến, không hoisted. Arrow function: cú pháp ngắn gọn, không có this riêng, không thể dùng làm constructor. Arrow function kế thừa this từ lexical scope bên ngoài." },
  { id: 227, category: "JavaScript", subcategory: "Functions", level: "beginner", q: "Callback function là gì? Tại sao JavaScript dùng callbacks?", a: "Callback là hàm được truyền vào hàm khác như argument để được gọi lại sau — ví dụ: `setTimeout(() => console.log('done'), 1000)` truyền arrow function làm callback. JavaScript dùng callbacks vì là single-threaded: thay vì chặn (block) chờ tác vụ dài như đọc file hay gọi API, JS đăng ký callback và tiếp tục chạy code khác, khi tác vụ xong thì gọi callback. Đây là nền tảng của lập trình bất đồng bộ trong JS, dù ngày nay đã có Promise và async/await thay thế cho các trường hợp phức tạp." },
  { id: 228, category: "JavaScript", subcategory: "Functions", level: "intermediate", q: "Higher-order function là gì? Cho ví dụ.", a: "Higher-order function là hàm nhận hàm khác làm argument hoặc trả về hàm. Ví dụ: map(), filter(), reduce() là HOF nhận callback. Hàm tạo middleware trong Express cũng là HOF. HOF là nền tảng của lập trình hàm (functional programming) trong JavaScript." },
  { id: 229, category: "JavaScript", subcategory: "Functions", level: "intermediate", q: "IIFE (Immediately Invoked Function Expression) là gì và dùng để làm gì?", a: "IIFE là hàm được định nghĩa và gọi ngay lập tức: `(function() { const secret = 42; })()` — biến secret không lọt ra global scope. Cú pháp arrow function: `(() => { ... })()`. Trước ES6, IIFE là cách duy nhất để tạo scope riêng vì chỉ có function scope. Dùng để: tránh ô nhiễm global scope, thực thi code khởi tạo một lần, tạo module pattern với private state. Ngày nay ít dùng hơn do có ES modules và block scope với `let`/`const`, nhưng vẫn hay gặp trong code cũ." },
  { id: 230, category: "JavaScript", subcategory: "Functions", level: "intermediate", q: "Pure function là gì? Tại sao pure functions quan trọng?", a: "Pure function là hàm luôn trả về kết quả giống nhau với cùng input và không có side effects — không thay đổi state ngoài, không gọi API, không modify argument truyền vào. Ví dụ: `const add = (a, b) => a + b` là pure, còn `const push = (arr, val) => { arr.push(val); return arr; }` là impure vì modify arr gốc. Pure functions dễ test (không cần mock), dễ debug, hỗ trợ memoization và là nền tảng của functional programming. Trong React, components và reducers nên là pure functions." },
  { id: 231, category: "JavaScript", subcategory: "Functions", level: "advanced", q: "Currying là gì? Cho ví dụ và trường hợp dùng thực tế.", a: "Currying chuyển hàm nhiều argument thành chuỗi hàm mỗi hàm nhận một argument: f(a,b,c) thành f(a)(b)(c). Ví dụ: `const multiply = (a) => (b) => a * b; const double = multiply(2); double(5) // 10`. Dùng cho partial application, compose functions, tạo hàm chuyên biệt." },
  { id: 232, category: "JavaScript", subcategory: "Functions", level: "advanced", q: "Memoization là gì? Cài đặt memoization đơn giản như thế nào?", a: "Memoization là kỹ thuật cache kết quả của hàm dựa trên input để tránh tính toán lại. Cài đặt: dùng Map hoặc object lưu {input: result}, kiểm tra cache trước khi tính. Hiệu quả với pure functions có tính toán nặng hoặc đệ quy như Fibonacci." },
  { id: 233, category: "JavaScript", subcategory: "Functions", level: "beginner", q: "Default parameters trong JavaScript là gì?", a: "Default parameters cho phép gán giá trị mặc định cho tham số khi không truyền vào hoặc truyền undefined: function greet(name = 'World'). Default value được evaluate tại runtime mỗi lần gọi hàm, không phải lúc định nghĩa, nên có thể là expression hoặc hàm gọi." },
  { id: 234, category: "JavaScript", subcategory: "Functions", level: "intermediate", q: "Rest parameters (...args) là gì? Khác gì arguments object?", a: "Rest parameters `(...args)` thu thập tất cả tham số còn lại thành Array thực sự: `function sum(...nums) { return nums.reduce((a, b) => a + b, 0); }`. Khác `arguments` object ở 3 điểm: rest là Array thật (có `map`, `filter`...) trong khi arguments chỉ là array-like; rest chỉ chứa các params chưa được đặt tên, còn arguments chứa tất cả; arrow functions không có `arguments` nhưng có rest params. Bẫy: rest param phải là tham số cuối cùng — `(a, ...rest, b)` là syntax error." },
  { id: 235, category: "JavaScript", subcategory: "Functions", level: "intermediate", q: "Function composition là gì?", a: "Function composition là tạo hàm mới bằng cách kết hợp nhiều hàm, output của hàm này là input của hàm kia: `compose(f, g)(x) = f(g(x))`. Ví dụ: `const process = compose(trim, toLowerCase, removeSpaces)` tạo pipeline xử lý string. Implement bằng reduce: `const compose = (...fns) => x => fns.reduceRight((v, f) => f(v), x)`. `pipe` là ngược chiều (trái sang phải, dễ đọc hơn). Hữu ích để tạo data transformation pipelines không cần biến trung gian, code theo functional style." },
  { id: 236, category: "JavaScript", subcategory: "Functions", level: "beginner", q: "Sự khác biệt giữa return và không có return trong arrow function là gì?", a: "Arrow function một dòng không có `{}` tự động return (implicit return): `x => x * 2`. Nếu có `{}` phải dùng return tường minh: `x => { return x * 2; }`. Bẫy phổ biến nhất: return object literal phải bọc trong ngoặc đơn `x => ({ value: x })` — nếu không có `()`, JS hiểu `{}` là function body chứ không phải object, hàm sẽ trả về undefined. Hay gặp khi dùng `.map()` để transform array thành array of objects." },
  { id: 237, category: "JavaScript", subcategory: "Functions", level: "advanced", q: "Generator function là gì? Dùng khi nào?", a: "Generator function dùng function* và yield, trả về iterator có thể pause và resume. Mỗi lần gọi next() thực thi đến yield tiếp theo và trả về {value, done}. Dùng để tạo infinite sequences, lazy evaluation, hoặc kiểm soát luồng bất đồng bộ (trước khi có async/await)." },
  { id: 238, category: "JavaScript", subcategory: "Functions", level: "intermediate", q: "Callback hell là gì? Các giải pháp để tránh?", a: "Callback hell là khi nhiều callbacks lồng nhau tạo code hình kim tự tháp, khó đọc và maintain — ví dụ: `getUser(id, (user) => getPosts(user, (posts) => getComments(posts[0], (comments) => ...)))`. Dễ xảy ra khi xử lý nhiều tác vụ async phụ thuộc nhau theo kiểu cũ. Giải pháp theo thứ tự ưu tiên: dùng async/await (rõ nhất), Promise chaining, hoặc named functions thay anonymous callbacks. Trong dự án thực tế, async/await là tiêu chuẩn hiện đại và nên dùng mặc định." },
  { id: 239, category: "JavaScript", subcategory: "Functions", level: "advanced", q: "Tail call optimization là gì?", a: "Tail call là khi hàm return kết quả của một lần gọi hàm khác trực tiếp. Tail call optimization (TCO) cho phép engine tái sử dụng stack frame thay vì tạo mới, tránh stack overflow trong đệ quy. ES6 quy định TCO nhưng chỉ Safari thực sự implement đầy đủ." },
  { id: 240, category: "JavaScript", subcategory: "Functions", level: "intermediate", q: "Function arity là gì?", a: "Arity là số lượng tham số mà hàm khai báo — truy cập qua `fn.length`. Lưu ý: `.length` chỉ đếm params trước default value hoặc rest param, ví dụ `(a, b = 1, ...c) => {}` có length là 1. Tên gọi: unary (1 arg), binary (2 args), ternary (3), variadic (không cố định). Arity quan trọng trong currying (cần biết bao nhiêu arg để auto-curry) và function composition. Bẫy phỏng vấn: `[1,2,3].map(parseInt)` trả về `[1, NaN, NaN]` vì parseInt nhận 2 args và map truyền vào (value, index)." },

  // === JavaScript: this & Binding (241-250) ===
  { id: 241, category: "JavaScript", subcategory: "this & Binding", level: "intermediate", q: "Quy tắc xác định giá trị của this trong JavaScript là gì?", a: "this được xác định theo 4 quy tắc ưu tiên giảm dần: 1) new binding (constructor), 2) explicit binding (call/apply/bind), 3) implicit binding (method call obj.fn()), 4) default binding (global/undefined trong strict mode). Arrow functions không có this riêng, kế thừa từ lexical scope." },
  { id: 242, category: "JavaScript", subcategory: "this & Binding", level: "beginner", q: "strict mode ảnh hưởng đến this như thế nào?", a: "Trong strict mode, this ở hàm thông thường là undefined thay vì global object (window/global). Điều này giúp phát hiện lỗi khi vô tình gọi hàm như function thay vì method. Kích hoạt bằng 'use strict'; ở đầu file hoặc hàm. ES modules tự động bật strict mode." },
  { id: 243, category: "JavaScript", subcategory: "this & Binding", level: "intermediate", q: "Sự khác biệt giữa call(), apply() và bind() là gì?", a: "`call(thisArg, arg1, arg2)` gọi hàm ngay với this chỉ định, truyền args riêng lẻ. `apply(thisArg, [arg1, arg2])` gọi ngay nhưng truyền args dạng array — mẹo nhớ: apply = array. `bind(thisArg)` trả về hàm mới với this cố định, không gọi ngay. Ví dụ thực tế: `const greet = function(greeting) { return greeting + ' ' + this.name; }; greet.call({name: 'An'}, 'Hello')` trả về 'Hello An'. bind thường dùng khi truyền method như callback: `btn.addEventListener('click', obj.method.bind(obj))`." },
  { id: 244, category: "JavaScript", subcategory: "this & Binding", level: "intermediate", q: "Tại sao arrow function không phù hợp làm method trong object?", a: "Arrow function không có this riêng, kế thừa this từ lexical scope nơi nó được định nghĩa (thường là global hoặc module). Khi dùng làm method, this không trỏ đến object chứa method. Dùng function thông thường cho methods, arrow function cho callbacks bên trong method." },
  { id: 245, category: "JavaScript", subcategory: "this & Binding", level: "intermediate", q: "Constructor function và new keyword hoạt động như thế nào?", a: "Khi gọi `new MyFunc()`, JS thực hiện 4 bước: 1) Tạo object rỗng mới, 2) Gán `MyFunc.prototype` làm prototype của object đó, 3) Chạy constructor với `this` là object mới, 4) Tự động return `this` — trừ khi constructor return tường minh một object khác. Ví dụ: `function Person(name) { this.name = name; } const p = new Person('An')` tạo object `{name: 'An'}` với `Person.prototype` trong prototype chain. Bẫy: quên `new` sẽ khiến `this` trỏ vào global object (hoặc undefined ở strict mode), gây bug khó tìm." },
  { id: 246, category: "JavaScript", subcategory: "this & Binding", level: "advanced", q: "Method borrowing (method stealing) là gì?", a: "Method borrowing là dùng call/apply để mượn method của một object áp dụng cho object khác. Ví dụ: Array.prototype.slice.call(arrayLike) để chuyển array-like thành array thực. Hoặc Object.prototype.toString.call(value) để lấy kiểu dữ liệu chính xác." },
  { id: 247, category: "JavaScript", subcategory: "this & Binding", level: "advanced", q: "Hard binding là gì?", a: "Hard binding là tạo wrapper function gọi hàm gốc với this cố định bằng apply/call, đảm bảo this không thay đổi. bind() tạo hard binding. Tuy nhiên, `new` operator là ngoại lệ duy nhất — new sẽ bỏ qua this đã bind và tạo instance mới." },
  { id: 248, category: "JavaScript", subcategory: "this & Binding", level: "beginner", q: "this trong class JavaScript là gì?", a: "Trong class, this trong constructor và methods trỏ đến instance được tạo. Tuy nhiên, khi truyền method như callback, mất this binding. Giải pháp: dùng arrow function trong class fields (class fields tự bind), hoặc bind trong constructor, hoặc dùng .bind() khi truyền callback." },
  { id: 249, category: "JavaScript", subcategory: "this & Binding", level: "intermediate", q: "Event handler và this hoạt động như thế nào?", a: "Khi gắn event handler bằng addEventListener, this trong handler trỏ đến DOM element nhận event. Nếu handler là arrow function, this kế thừa từ context bên ngoài. Khi dùng class methods làm event handler cần bind hoặc dùng arrow function để giữ this của instance." },
  { id: 250, category: "JavaScript", subcategory: "this & Binding", level: "advanced", q: "Soft binding là gì và khác hard binding như thế nào?", a: "Soft binding cho phép ghi đè this binding (khác hard binding không thể ghi đè) nhưng fallback về giá trị mặc định thay vì global. Implement bằng cách kiểm tra this trong wrapper: nếu là global/undefined thì dùng default. Ít dùng thực tế, chủ yếu trong thư viện." },

  // === JavaScript: Prototype (251-260) ===
  { id: 251, category: "JavaScript", subcategory: "Prototype", level: "intermediate", q: "Prototype chain trong JavaScript là gì?", a: "Mỗi object có [[Prototype]] internal slot trỏ đến prototype object. Khi truy cập property không tìm thấy trên object, JS tìm lên prototype, rồi prototype của prototype, cho đến khi gặp null. Đây là cơ chế kế thừa của JavaScript, khác với class-based inheritance." },
  { id: 252, category: "JavaScript", subcategory: "Prototype", level: "beginner", q: "__proto__ và prototype khác nhau như thế nào?", a: "__proto__ là accessor property trên object instance trỏ đến prototype của nó. prototype là property trên function (constructor), là object sẽ được gán cho __proto__ của instance khi dùng new. Object.getPrototypeOf() là cách chuẩn để truy cập __proto__." },
  { id: 253, category: "JavaScript", subcategory: "Prototype", level: "intermediate", q: "Object.create() hoạt động như thế nào?", a: "Object.create(proto) tạo object mới với [[Prototype]] được set thành proto. Cho phép kế thừa trực tiếp từ object cụ thể mà không cần constructor. Object.create(null) tạo object không có prototype nào, dùng làm pure dictionary. Đây là cách implement prototypal inheritance thuần túy." },
  { id: 254, category: "JavaScript", subcategory: "Prototype", level: "intermediate", q: "Prototypal inheritance khác class-based inheritance như thế nào?", a: "Class-based inheritance (Java, C++) tạo bản sao của class blueprint. Prototypal inheritance: objects kế thừa trực tiếp từ objects khác qua prototype chain, không có blueprint. JavaScript classes (ES6) chỉ là syntactic sugar trên prototypal inheritance, bên dưới vẫn dùng prototype." },
  { id: 255, category: "JavaScript", subcategory: "Prototype", level: "intermediate", q: "instanceof operator hoạt động như thế nào?", a: "instanceof kiểm tra xem prototype của constructor có xuất hiện trong prototype chain của object không: obj instanceof Constructor kiểm tra Constructor.prototype có trong chain của obj. Có thể tùy chỉnh bằng Symbol.hasInstance. Không đáng tin cậy khi làm việc với nhiều realms (iframe, vm)." },
  { id: 256, category: "JavaScript", subcategory: "Prototype", level: "advanced", q: "hasOwnProperty() và in operator khác nhau như thế nào?", a: "hasOwnProperty() kiểm tra property có trực tiếp trên object hay không, không kiểm tra prototype chain. in operator kiểm tra cả object lẫn toàn bộ prototype chain. Object.hasOwn() là cách mới hơn, an toàn hơn hasOwnProperty() vì không bị ghi đè." },
  { id: 257, category: "JavaScript", subcategory: "Prototype", level: "advanced", q: "Prototype pollution là gì và cách phòng tránh?", a: "Prototype pollution xảy ra khi kẻ tấn công thêm property vào Object.prototype, ảnh hưởng đến tất cả objects. Thường qua merge/clone functions không an toàn (obj[key] = value với key là __proto__). Phòng tránh: dùng Object.create(null), kiểm tra key, dùng Map thay object, freeze prototype." },
  { id: 258, category: "JavaScript", subcategory: "Prototype", level: "intermediate", q: "Object.setPrototypeOf() có hiệu suất tốt không?", a: "Object.setPrototypeOf() thay đổi prototype sau khi tạo object, gây ảnh hưởng nghiêm trọng đến hiệu suất vì V8 engine không thể tối ưu hóa (hidden classes bị vô hiệu hóa). Tốt hơn là dùng Object.create() khi tạo để set prototype ngay từ đầu." },
  { id: 259, category: "JavaScript", subcategory: "Prototype", level: "advanced", q: "Mixin pattern trong JavaScript là gì?", a: "Mixin là cách thêm behavior vào object/class mà không dùng kế thừa đơn. Implement bằng Object.assign() để copy methods vào prototype, hoặc dùng higher-order functions nhận class và trả về class mở rộng. Giải quyết vấn đề diamond problem của đa kế thừa." },
  { id: 260, category: "JavaScript", subcategory: "Prototype", level: "intermediate", q: "Tại sao không nên extend built-in prototypes?", a: "Extending built-in prototypes (Array.prototype.myMethod) có thể xung đột với future JavaScript features, gây bug trong thư viện bên thứ ba chia sẻ environment, và khó debug. Thay vào đó dùng utility functions, subclassing với class extends, hoặc wrapper classes." },

  // === JavaScript: ES6+ (261-280) ===
  { id: 261, category: "JavaScript", subcategory: "ES6+", level: "beginner", q: "Destructuring assignment là gì? Cho ví dụ với array và object.", a: "Destructuring cho phép giải nén giá trị từ array/object vào biến riêng lẻ. Array: const [a, b] = [1, 2]. Object: const {name, age} = person. Hỗ trợ default values, alias, và nested destructuring. Rất hữu ích với function parameters và khi làm việc với API responses." },
  { id: 262, category: "JavaScript", subcategory: "ES6+", level: "beginner", q: "Spread operator (...) và rest parameters (...) khác nhau như thế nào?", a: "Spread mở rộng iterable thành từng phần tử riêng lẻ (dùng trong function calls, array literals, object literals). Rest thu thập nhiều phần tử thành một array (dùng trong function parameters). Cú pháp giống nhau nhưng ngữ cảnh ngược nhau: spread 'mở ra', rest 'thu lại'." },
  { id: 263, category: "JavaScript", subcategory: "ES6+", level: "beginner", q: "Template literals là gì? Có những tính năng gì?", a: "Template literals dùng backtick (`) thay dấu nháy, hỗ trợ: interpolation ${expression}, multi-line strings không cần \\n, tagged templates (cho styled-components, SQL query builders). Tagged templates là function nhận template strings và expressions làm arguments." },
  { id: 264, category: "JavaScript", subcategory: "ES6+", level: "beginner", q: "Class trong ES6 là gì? Có điểm gì khác với function constructor?", a: "Class là cú pháp OOP rõ ràng hơn để tạo objects: `class Animal { constructor(name) { this.name = name; } speak() { return this.name + ' speaks'; } }`. Khác function constructor ở chỗ: class không thể gọi không có `new` (throw TypeError), methods trong class không enumerable (không xuất hiện trong for...in), và phải khai báo trước khi dùng (không hoisted). Bên dưới vẫn dùng prototype chain — class chỉ là syntactic sugar. Nên dùng class thay function constructor trong code hiện đại vì rõ ràng và có thêm private fields (#), static methods." },
  { id: 265, category: "JavaScript", subcategory: "ES6+", level: "intermediate", q: "Private class fields (#) là gì?", a: "Private fields khai báo với # prefix chỉ có thể truy cập trong class: #name. Không thể truy cập từ bên ngoài kể cả subclass, ném SyntaxError. Đây là private thực sự (khác convention _ prefix), được implement ở engine level. Cũng có private methods (#method()) và static private." },
  { id: 266, category: "JavaScript", subcategory: "ES6+", level: "beginner", q: "for...of và for...in khác nhau như thế nào?", a: "for...in lặp qua enumerable property names của object (và prototype chain). for...of lặp qua values của iterable objects (Array, String, Map, Set, Generator). for...of thường dùng cho arrays, for...in cho objects. Tránh for...in với arrays do có thể lặp qua inherited properties." },
  { id: 267, category: "JavaScript", subcategory: "ES6+", level: "intermediate", q: "Map và WeakMap khác nhau như thế nào?", a: "Map lưu key-value với key là bất kỳ type nào, iterable, có size. WeakMap chỉ nhận objects làm key, không iterable, không có size. Key trong WeakMap là weak reference: nếu object bị garbage collect, entry tự động bị xóa. WeakMap dùng để associate data với object mà không ngăn GC." },
  { id: 268, category: "JavaScript", subcategory: "ES6+", level: "intermediate", q: "Set và WeakSet là gì?", a: "Set lưu collection của unique values bất kỳ type nào, iterable, có size. WeakSet chỉ chứa objects, không iterable, weak references (tránh memory leak). Set dùng để loại bỏ duplicate, kiểm tra membership nhanh. WeakSet dùng để track objects mà không ngăn GC." },
  { id: 269, category: "JavaScript", subcategory: "ES6+", level: "intermediate", q: "Optional chaining (?.) và nullish coalescing (??) là gì?", a: "Optional chaining `obj?.prop` trả về undefined thay vì throw TypeError nếu obj là null/undefined — ví dụ `user?.address?.city` an toàn kể cả khi user hoặc address là null. Nullish coalescing `a ?? b` trả về b chỉ khi a là null/undefined, khác `||` vốn trả về b với mọi falsy (0, '', false). Kết hợp cả hai: `user?.profile?.age ?? 18` để lấy tuổi hoặc default 18. Bẫy: `0 || 5` trả về 5 nhưng `0 ?? 5` trả về 0 — dùng ?? khi 0 hoặc chuỗi rỗng là giá trị hợp lệ." },
  { id: 270, category: "JavaScript", subcategory: "ES6+", level: "beginner", q: "ES modules (import/export) là gì?", a: "ES modules là hệ thống module chính thức của JavaScript. export để export bindings, import để import. Static analysis: imports/exports được phân tích tại parse time, không thể dynamic (dùng import() cho dynamic). Module có own scope, strict mode by default, live bindings." },
  { id: 271, category: "JavaScript", subcategory: "ES6+", level: "intermediate", q: "Proxy và Reflect trong ES6 là gì?", a: "Proxy bọc object và chặn các operation (get, set, has, deleteProperty...) bằng handler traps. Reflect cung cấp methods tương ứng với các traps. Dùng để tạo reactive objects (Vue 3), validation, logging, lazy initialization, hay implement Observable." },
  { id: 272, category: "JavaScript", subcategory: "ES6+", level: "advanced", q: "Symbol.iterator và iterable protocol là gì?", a: "Iterable protocol yêu cầu object có method Symbol.iterator trả về iterator object (có next() trả về {value, done}). Arrays, Strings, Maps, Sets implement sẵn. Custom iterables cho phép dùng for...of, spread, destructuring. Generator functions tự động tạo iterable." },
  { id: 273, category: "JavaScript", subcategory: "ES6+", level: "advanced", q: "Tagged template literals hoạt động như thế nào?", a: "Tagged template là hàm gọi với template: tag`text ${expr}`. Hàm nhận (strings, ...values) - strings là mảng các phần text tĩnh, values là các expressions. Dùng trong styled-components (CSS-in-JS), sql template literals (prevent injection), i18n, highlight code." },
  { id: 274, category: "JavaScript", subcategory: "ES6+", level: "intermediate", q: "Object.assign() và spread operator khi copy object khác nhau như thế nào?", a: "Cả hai đều shallow copy. Object.assign() copy vào object đích hiện có, trigger setters. Spread tạo plain object mới, không trigger setters. Object.assign() copy enumerable own properties bao gồm cả Symbol. Với nested objects, cả hai chỉ copy reference, không deep copy." },
  { id: 275, category: "JavaScript", subcategory: "ES6+", level: "intermediate", q: "Array destructuring với swap variables hoạt động như thế nào?", a: "Destructuring cho phép swap không cần temp variable: `[a, b] = [b, a]`. Cú pháp này tạo array mới từ [b, a] rồi destructure vào a và b cùng lúc, khác hoàn toàn cách truyền thống phải dùng biến tạm `let tmp = a; a = b; b = tmp`. Quan trọng trong thuật toán sắp xếp (như bubble sort) vì giúp code ngắn gọn và ít lỗi hơn. Phỏng vấn hay hỏi về destructuring nâng cao — nên biết cả nested destructuring và default values." },
  { id: 276, category: "JavaScript", subcategory: "ES6+", level: "advanced", q: "Logical assignment operators (&&=, ||=, ??=) là gì?", a: "Logical assignment kết hợp phép logic với phép gán. `&&=` gán chỉ khi bên trái truthy: `user.name &&= user.name.trim()` — chỉ trim nếu name có giá trị. `||=` gán khi bên trái falsy: `config.timeout ||= 3000` để đặt default. `??=` gán chỉ khi null/undefined (an toàn hơn ||= vì không ghi đè 0 hay ''): `options.retries ??= 3`. Sự khác biệt quan trọng với ||= và ??=: nếu giá trị là 0 hoặc chuỗi rỗng, ||= sẽ ghi đè còn ??= thì không." },
  { id: 277, category: "JavaScript", subcategory: "ES6+", level: "advanced", q: "Array.from() vs spread operator khi chuyển đổi array-like là gì?", a: "Array.from(arrayLike) và [...arrayLike] đều tạo array từ iterable. Array.from() mạnh hơn: nhận array-like không phải iterable (có length và indexed), có tham số mapFn để transform, xử lý undefined holes. Spread yêu cầu đúng iterable protocol." },
  { id: 278, category: "JavaScript", subcategory: "ES6+", level: "intermediate", q: "Object shorthand properties và computed property names là gì?", a: "Shorthand: nếu tên biến trùng key thì viết `{name}` thay `{name: name}` — rất phổ biến khi return object từ hàm: `return {id, name, email}`. Computed property names dùng [] để tính key động: `{[fieldName]: value}` cho phép key là biểu thức bất kỳ. Ví dụ thực tế: `const update = (key, val) => ({...state, [key]: val})` để update state theo key động. Cả hai tính năng này xuất hiện rất nhiều trong React và Redux code." },
  { id: 279, category: "JavaScript", subcategory: "ES6+", level: "beginner", q: "String methods mới trong ES6+ như padStart, padEnd, includes, startsWith là gì?", a: "`includes(str)` kiểm tra có chứa substring không (thay indexOf !== -1). `startsWith(str)` / `endsWith(str)` kiểm tra đầu/cuối chuỗi. `padStart(len, char)` / `padEnd(len, char)` thêm ký tự vào đầu/cuối cho đủ độ dài — ví dụ `'5'.padStart(3, '0')` cho ra `'005'`, hữu ích để format số thứ tự. `trimStart()` / `trimEnd()` xóa whitespace một phía. `replaceAll(old, new)` thay thế tất cả occurrences, khác `replace()` chỉ thay lần đầu. Những methods này giúp code ngắn và dễ đọc hơn nhiều so với regex." },
  { id: 280, category: "JavaScript", subcategory: "ES6+", level: "intermediate", q: "at() method cho Array và String là gì?", a: "`at(index)` truy cập phần tử với hỗ trợ negative index: `arr.at(-1)` lấy phần tử cuối, `arr.at(-2)` lấy phần tử áp cuối. Thay cho `arr[arr.length - 1]` vốn dài và dễ nhầm khi tính toán. Hoạt động với Array, String và TypedArray, không thay đổi mảng gốc. Không thể dùng cú pháp bracket `arr[-1]` vì JS sẽ coi -1 là string key của object, không phải index âm — đây là bẫy phỏng vấn phổ biến." },

  // === JavaScript: Promise & Async (281-300) ===
  { id: 281, category: "JavaScript", subcategory: "Promise & Async", level: "beginner", q: "Promise là gì? Có những trạng thái nào?", a: "Promise đại diện cho kết quả của một tác vụ bất đồng bộ sẽ có trong tương lai. Ba trạng thái: pending (đang chờ), fulfilled (thành công với giá trị), rejected (thất bại với lý do). Một khi fulfilled/rejected, trạng thái không thay đổi (immutable). Dùng .then()/.catch()/.finally() để handle." },
  { id: 282, category: "JavaScript", subcategory: "Promise & Async", level: "beginner", q: ".then(), .catch() và .finally() hoạt động như thế nào?", a: "`.then(onFulfilled, onRejected)` nhận callback khi promise fulfilled hoặc rejected. `.catch(onRejected)` là shorthand cho `.then(null, onRejected)` — chỉ xử lý lỗi. `.finally(callback)` chạy dù fulfilled hay rejected, không nhận value, dùng để cleanup (ẩn loading spinner, đóng connection). Tất cả đều trả về Promise mới nên có thể chain tiếp. Bẫy phổ biến: không thêm `.catch()` ở cuối chain dẫn đến unhandled rejection — luôn kết thúc chain bằng `.catch()` trong production code." },
  { id: 283, category: "JavaScript", subcategory: "Promise & Async", level: "intermediate", q: "Promise.all(), Promise.race(), Promise.allSettled() và Promise.any() khác nhau như thế nào?", a: "all(): chờ tất cả fulfilled, reject ngay khi có một reject (fail-fast). race(): resolve hoặc reject ngay khi có promise đầu tiên settle (fulfilled hoặc rejected). allSettled(): chờ tất cả settle (fulfilled hoặc rejected), không reject. any(): resolve với promise đầu tiên fulfilled, reject khi tất cả reject (AggregateError)." },
  { id: 284, category: "JavaScript", subcategory: "Promise & Async", level: "advanced", q: "Event loop trong JavaScript hoạt động như thế nào?", a: "JS single-threaded nhưng xử lý async nhờ event loop. Quy trình: (1) Chạy hết sync code trên Call Stack. (2) Xử lý hết Microtask queue (Promise.then, queueMicrotask, MutationObserver). (3) Browser có thể render (paint). (4) Lấy 1 Macrotask (setTimeout, setInterval, I/O events). (5) Quay lại bước 2. Lưu ý: microtasks luôn ưu tiên hơn macrotasks — `Promise.resolve().then()` chạy trước `setTimeout(fn, 0)`." },
  { id: 285, category: "JavaScript", subcategory: "Promise & Async", level: "intermediate", q: "Microtask và macrotask khác nhau như thế nào?", a: "Microtasks: Promise callbacks (.then, .catch), queueMicrotask(), MutationObserver. Macrotasks (tasks): setTimeout, setInterval, setImmediate (Node.js), I/O callbacks, UI rendering. Sau mỗi macrotask, tất cả microtasks trong queue được xử lý hết. Thứ tự: sync code → microtasks → render → macrotask → ..." },
  { id: 286, category: "JavaScript", subcategory: "Promise & Async", level: "beginner", q: "async/await là gì? Tại sao nó dễ hơn Promise chains?", a: "async/await là syntactic sugar trên Promises. async function luôn trả về Promise. await dừng thực thi trong async function cho đến khi Promise resolve, trả về resolved value. Code trông như synchronous nhưng vẫn non-blocking. Dễ đọc hơn, dễ debug hơn, xử lý lỗi với try/catch tự nhiên hơn." },
  { id: 287, category: "JavaScript", subcategory: "Promise & Async", level: "intermediate", q: "Xử lý lỗi trong async/await như thế nào?", a: "Dùng try/catch bọc await expressions. Lỗi từ rejected Promise được catch như exception. Có thể chain .catch() trên async function call bên ngoài. Cần cẩn thận với parallel awaits trong try/catch: await Promise.all([a, b]) để handle lỗi từ cả hai đồng thời." },
  { id: 288, category: "JavaScript", subcategory: "Promise & Async", level: "advanced", q: "Debounce và throttle là gì? Khi nào dùng cái nào?", a: "Debounce: chỉ gọi hàm sau khi ngừng trigger một khoảng thời gian (dùng cho search input, resize). Throttle: gọi hàm tối đa một lần trong khoảng thời gian nhất định (dùng cho scroll, mousemove). Debounce = 'đợi nghỉ', throttle = 'giới hạn tần suất'." },
  { id: 289, category: "JavaScript", subcategory: "Promise & Async", level: "advanced", q: "Promise executor chạy synchronously hay asynchronously?", a: "Promise executor (function truyền vào new Promise()) chạy synchronously ngay lập tức. Nhưng callbacks .then()/.catch() luôn chạy asynchronously (microtask queue), kể cả khi Promise đã resolve. Điều này đảm bảo behavior nhất quán dù Promise resolve sync hay async." },
  { id: 290, category: "JavaScript", subcategory: "Promise & Async", level: "intermediate", q: "Promise chaining và error propagation hoạt động như thế nào?", a: "Trong chain, error propagate đến .catch() gần nhất tiếp theo. Sau .catch(), chain tiếp tục bình thường. Trả về rejected promise hoặc throw trong .then() cũng tiếp tục propagate. Nếu không có .catch(), unhandledRejection event được fired (crash trong Node.js)." },
  { id: 291, category: "JavaScript", subcategory: "Promise & Async", level: "advanced", q: "Async iteration (for await...of) là gì?", a: "for await...of lặp qua async iterable - objects implement Symbol.asyncIterator trả về async iterator. Mỗi iteration await giá trị tiếp theo. Dùng với streams, pagination APIs, WebSocket messages. Async generators (async function*) tạo async iterables dễ dàng." },
  { id: 292, category: "JavaScript", subcategory: "Promise & Async", level: "intermediate", q: "setTimeout(fn, 0) có thực sự chạy ngay không?", a: "Không, setTimeout(fn, 0) vẫn đưa callback vào macrotask queue, chạy sau khi call stack rỗng và tất cả microtasks xử lý xong. Thực tế delay tối thiểu thường là 4ms trong browser (HTML spec). Dùng queueMicrotask() nếu muốn chạy sớm hơn (sau sync code nhưng trước I/O)." },
  { id: 293, category: "JavaScript", subcategory: "Promise & Async", level: "advanced", q: "Abort controller dùng để hủy fetch request như thế nào?", a: "AbortController tạo controller và signal. Truyền signal vào fetch options, khi gọi controller.abort() request bị hủy với AbortError. Quan trọng khi component unmount (React useEffect cleanup), search với debounce, hay race conditions. Cũng dùng được với các APIs khác nhận AbortSignal." },
  { id: 294, category: "JavaScript", subcategory: "Promise & Async", level: "intermediate", q: "Promise.resolve() và Promise.reject() dùng để làm gì?", a: "Promise.resolve(value) trả về Promise đã fulfilled với value (nếu value là Promise/thenable, unwrap nó). Promise.reject(reason) trả về Promise đã rejected. Hữu ích để tạo Promise ngay lập tức, normalize value (có thể là Promise hoặc plain value), và trong testing." },
  { id: 295, category: "JavaScript", subcategory: "Promise & Async", level: "advanced", q: "Thenable là gì?", a: "Thenable là object có method .then(). Promise resolution procedure unwrap thenables: khi resolve với thenable, gọi .then() của nó. Cho phép interop giữa các Promise implementations khác nhau. Nếu thenable throw trong .then(), Promise bị rejected. Đây là cách jQuery Deferred hoạt động với native Promises." },
  { id: 296, category: "JavaScript", subcategory: "Promise & Async", level: "intermediate", q: "Race condition trong async JavaScript là gì và cách xử lý?", a: "Race condition xảy ra khi nhiều async operations chạy đồng thời và kết quả phụ thuộc vào thứ tự hoàn thành. Cách xử lý: dùng AbortController hủy requests cũ, track request ID và bỏ qua responses không mới nhất, dùng debounce, hoặc mutex/semaphore pattern." },
  { id: 297, category: "JavaScript", subcategory: "Promise & Async", level: "advanced", q: "async/await với parallel execution như thế nào?", a: "await tuần tự từng operation sẽ chậm hơn. Chạy song song: tạo tất cả Promises trước rồi await: const [a, b] = await Promise.all([fetchA(), fetchB()]). Tránh await trong loop (for...of với await là serial), dùng Promise.all(items.map(fn)) cho parallel." },
  { id: 298, category: "JavaScript", subcategory: "Promise & Async", level: "intermediate", q: "Unhandled promise rejection là gì? Cách xử lý?", a: "Unhandled rejection xảy ra khi Promise bị rejected mà không có .catch() handler. Trong Node.js v15+ sẽ terminate process theo mặc định (cấu hình qua --unhandled-rejections flag), trong browser hiện warning. Xử lý: luôn thêm .catch(), dùng process.on('unhandledRejection'), window.addEventListener('unhandledrejection'). Tốt nhất: luôn handle errors tại source." },
  { id: 299, category: "JavaScript", subcategory: "Promise & Async", level: "advanced", q: "Task scheduling trong JavaScript: requestAnimationFrame và requestIdleCallback là gì?", a: "requestAnimationFrame(cb) chạy callback trước lần repaint tiếp theo (~16ms), dùng cho animations để sync với display refresh. requestIdleCallback(cb) chạy khi browser idle giữa frames, dùng cho non-urgent tasks như analytics, prefetch. Cả hai quan trọng cho performance." },
  { id: 300, category: "JavaScript", subcategory: "Promise & Async", level: "advanced", q: "Long tasks và JavaScript performance liên quan đến event loop như thế nào?", a: "Tasks chiếm hơn 50ms là long tasks, block main thread, gây jank (giật). Giải pháp: chia nhỏ tasks với setTimeout(0) hoặc scheduler.yield() (mới), sử dụng Web Workers cho heavy computation, dùng requestIdleCallback cho background tasks. Chrome DevTools performance tab hiển thị long tasks." },

  // === JavaScript: DOM & APIs (301-320) ===
  { id: 301, category: "JavaScript", subcategory: "DOM & APIs", level: "beginner", q: "DOM là gì? JavaScript tương tác với DOM như thế nào?", a: "DOM (Document Object Model) là biểu diễn dạng cây của HTML document, mỗi element là một node. JavaScript tương tác qua document API: querySelector, createElement, appendChild, setAttribute... DOM manipulation là synchronous, thay đổi DOM ngay lập tức reflect trên page." },
  { id: 302, category: "JavaScript", subcategory: "DOM & APIs", level: "beginner", q: "Sự khác biệt giữa getElementById, querySelector và querySelectorAll là gì?", a: "getElementById trả về element đầu tiên có id, nhanh nhất. querySelector trả về element đầu tiên khớp CSS selector. querySelectorAll trả về NodeList tất cả elements khớp (static, không live). getElementsByClassName và getElementsByTagName trả về HTMLCollection (live). querySelectorAll phổ biến nhất vì linh hoạt." },
  { id: 303, category: "JavaScript", subcategory: "DOM & APIs", level: "intermediate", q: "Event bubbling và event capturing là gì?", a: "Events propagate qua 3 phase: capturing (từ window xuống target), target, bubbling (từ target lên window). Mặc định addEventListener ở bubbling phase (useCapture = false). Capturing ít dùng nhưng xử lý trước bubbling. stopPropagation() dừng propagation, stopImmediatePropagation() dừng cả handlers cùng element." },
  { id: 304, category: "JavaScript", subcategory: "DOM & APIs", level: "intermediate", q: "Event delegation là gì? Tại sao nó hiệu quả?", a: "Event delegation gắn một event listener lên parent thay vì nhiều listeners trên từng child. Dựa vào event bubbling, check event.target để xác định element nào được click. Hiệu quả hơn cho dynamic content (không cần re-attach), ít memory hơn, code sạch hơn." },
  { id: 305, category: "JavaScript", subcategory: "DOM & APIs", level: "beginner", q: "preventDefault() và stopPropagation() khác nhau như thế nào?", a: "preventDefault() ngăn hành vi mặc định của browser (submit form, follow link, check checkbox) nhưng không dừng propagation. stopPropagation() ngăn event bubble/capture lên/xuống DOM tree nhưng không ngăn default behavior. Có thể dùng cả hai cùng lúc." },
  { id: 306, category: "JavaScript", subcategory: "DOM & APIs", level: "intermediate", q: "Fetch API là gì? Khác XMLHttpRequest như thế nào?", a: "Fetch API là interface Promise-based hiện đại cho HTTP requests. Khác XHR: Promise thay callbacks, cleaner API, hỗ trợ service workers, streams. Lưu ý: Fetch không reject khi HTTP error (404, 500), chỉ reject với network failure - cần check response.ok. XHR hỗ trợ progress events và request cancellation dễ hơn." },
  { id: 307, category: "JavaScript", subcategory: "DOM & APIs", level: "beginner", q: "localStorage và sessionStorage khác nhau như thế nào?", a: "localStorage: persist qua sessions, chỉ bị xóa manually hoặc qua code, shared across tabs cùng origin. sessionStorage: xóa khi đóng tab/window, riêng biệt cho từng tab. Cả hai đồng bộ (synchronous), chỉ lưu string, giới hạn ~5MB. Dùng JSON.stringify/parse để lưu objects." },
  { id: 308, category: "JavaScript", subcategory: "DOM & APIs", level: "intermediate", q: "Web Workers là gì? Khi nào nên dùng?", a: "Web Workers chạy JavaScript trong background thread riêng biệt, không block main thread. Giao tiếp qua postMessage. Không truy cập được DOM. Dùng cho: heavy computation (image processing, encryption, data parsing), keeping UI responsive. SharedArrayBuffer cho phép share memory giữa workers." },
  { id: 309, category: "JavaScript", subcategory: "DOM & APIs", level: "intermediate", q: "IntersectionObserver API là gì và dùng để làm gì?", a: "IntersectionObserver theo dõi khi element đi vào/ra viewport hoặc ancestor element. Asynchronous, không block main thread, hiệu quả hơn scroll event listeners. Dùng cho: lazy loading images, infinite scroll, animations triggered by scroll, tracking ad visibility." },
  { id: 310, category: "JavaScript", subcategory: "DOM & APIs", level: "intermediate", q: "MutationObserver là gì?", a: "MutationObserver theo dõi thay đổi trên DOM tree (attribute changes, child additions/removals, text changes). Asynchronous, callbacks chạy như microtask. Hữu ích khi làm việc với third-party code thay đổi DOM, implement undo/redo, hay real-time updates. ResizeObserver theo dõi thay đổi kích thước element." },
  { id: 311, category: "JavaScript", subcategory: "DOM & APIs", level: "beginner", q: "Cookie, localStorage và sessionStorage khác nhau như thế nào về bảo mật và sử dụng?", a: "Cookies gửi kèm mọi HTTP request (có thể dùng HttpOnly để ngăn JS access, Secure cho HTTPS only). LocalStorage/sessionStorage chỉ accessible qua JS, không gửi với requests. Cookies cho session, auth tokens. LocalStorage cho user preferences, cache. Tránh lưu sensitive data trong localStorage vì XSS." },
  { id: 312, category: "JavaScript", subcategory: "DOM & APIs", level: "intermediate", q: "Custom events trong JavaScript là gì?", a: "CustomEvent cho phép tạo events tùy chỉnh: new CustomEvent('myEvent', {detail: {data}}). Dispatch với element.dispatchEvent(event). Bubbles và cancelable tùy chỉnh được. Dùng cho component communication không dùng framework, pub/sub pattern trong vanilla JS." },
  { id: 313, category: "JavaScript", subcategory: "DOM & APIs", level: "intermediate", q: "requestAnimationFrame là gì và tại sao nên dùng thay setTimeout cho animations?", a: "requestAnimationFrame(callback) lên lịch callback trước repaint tiếp theo (~60fps). Tự pause khi tab ẩn (tiết kiệm CPU/battery), sync với display refresh rate, smooth hơn setTimeout. Trả về ID để cancelAnimationFrame. Callback nhận timestamp để tính delta time." },
  { id: 314, category: "JavaScript", subcategory: "DOM & APIs", level: "advanced", q: "Service Workers là gì?", a: "Service Worker là script chạy trong background, tách khỏi web page, không có DOM access. Có thể intercept network requests (cache strategy), enable offline functionality, background sync, push notifications. Là nền tảng của PWA. Chỉ hoạt động trên HTTPS, có lifecycle riêng (install, activate, fetch)." },
  { id: 315, category: "JavaScript", subcategory: "DOM & APIs", level: "intermediate", q: "Sự khác biệt giữa textContent, innerText và innerHTML là gì?", a: "innerHTML: get/set HTML markup (nguy cơ XSS nếu set user input). textContent: get/set text của tất cả nodes kể cả ẩn, không trigger reflow. innerText: chỉ lấy text hiển thị (aware of CSS), trigger reflow để tính style. textContent nhanh nhất và an toàn nhất cho text manipulation." },
  { id: 316, category: "JavaScript", subcategory: "DOM & APIs", level: "intermediate", q: "DocumentFragment là gì và tại sao nó tốt cho performance?", a: "DocumentFragment là node nhẹ không thuộc DOM chính. Thêm nhiều elements vào fragment, rồi append fragment một lần vào DOM. Tránh nhiều reflow/repaint vì DOM chỉ cập nhật một lần. Khi fragment được append, nó trở nên rỗng và children chuyển vào DOM." },
  { id: 317, category: "JavaScript", subcategory: "DOM & APIs", level: "advanced", q: "Broadcast Channel API là gì?", a: "Broadcast Channel cho phép giao tiếp giữa các browsing contexts (tabs, windows, iframes) cùng origin. Dùng new BroadcastChannel('name') và postMessage/onmessage. Khác localStorage events (chỉ fire ở tabs khác), Broadcast Channel fire ở tất cả subscribers. Dùng cho sync state giữa tabs." },
  { id: 318, category: "JavaScript", subcategory: "DOM & APIs", level: "beginner", q: "Sự khác biệt giữa window, document và navigator là gì?", a: "window: global object trong browser, chứa tất cả global APIs (alert, setTimeout, location). document: DOM tree của trang hiện tại, child của window. navigator: thông tin về browser/OS (userAgent, language, online status, geolocation). window.screen chứa info về màn hình." },
  { id: 319, category: "JavaScript", subcategory: "DOM & APIs", level: "intermediate", q: "History API (pushState, replaceState) là gì?", a: "History API cho phép thay đổi URL và lịch sử navigation mà không reload page. pushState() thêm entry mới vào history, replaceState() thay đổi entry hiện tại. popstate event fires khi navigate back/forward. Là nền tảng của client-side routing trong SPAs." },
  { id: 320, category: "JavaScript", subcategory: "DOM & APIs", level: "advanced", q: "IndexedDB là gì? Khi nào dùng thay localStorage?", a: "IndexedDB là database NoSQL trong browser hỗ trợ: lưu structured data (objects, files, blobs), indexes, transactions, large data. Asynchronous, không block main thread. Dùng khi cần: lưu > 5MB, query phức tạp, offline-first apps. Phức tạp hơn localStorage nhiều, có thể dùng thư viện như Dexie.js." },

  // === TypeScript: Types Cơ Bản (321-335) ===
  { id: 321, category: "TypeScript", subcategory: "Types Cơ Bản", level: "beginner", q: "TypeScript là gì và tại sao nên dùng TypeScript thay JavaScript?", a: "TypeScript là superset của JavaScript có static typing, compile sang JS. Lợi ích: phát hiện lỗi tại compile time, IDE support tốt hơn (autocomplete, refactoring), code tự documentation hóa. Không thay thế JS mà enhance nó. Hữu ích nhất ở dự án lớn, team, và codebases cần maintain lâu dài." },
  { id: 322, category: "TypeScript", subcategory: "Types Cơ Bản", level: "beginner", q: "Type annotation trong TypeScript là gì?", a: "Type annotation là khai báo kiểu tường minh cho biến, parameter, return value: let name: string = 'John'. TypeScript cũng có type inference tự suy luận kiểu từ giá trị gán. Annotation thường chỉ cần cho function parameters, return types, và khi inference không đủ thông tin." },
  { id: 323, category: "TypeScript", subcategory: "Types Cơ Bản", level: "beginner", q: "any, unknown và never khác nhau như thế nào?", a: "any: tắt type checking, không an toàn, tránh dùng. unknown: type-safe any, phải kiểm tra type trước khi dùng, không thể assign cho typed variable mà không narrow. never: không bao giờ có giá trị, dùng cho hàm luôn throw, hoặc exhaustive checks. unknown >> any về safety." },
  { id: 324, category: "TypeScript", subcategory: "Types Cơ Bản", level: "beginner", q: "Union types và intersection types là gì?", a: "Union type `A | B`: value có thể là A hoặc B — ví dụ `string | number` cho phép cả hai. Intersection type `A & B`: value phải có tất cả properties của A lẫn B — ví dụ `type AdminUser = User & { adminRole: string }` tạo type có đủ fields của User cộng thêm adminRole. Union dùng khi một giá trị có thể là nhiều loại (parameter linh hoạt), intersection dùng khi cần combine nhiều interface/type lại. Bẫy: intersection của 2 primitive types không tương thích (như `string & number`) cho ra type `never`." },
  { id: 325, category: "TypeScript", subcategory: "Types Cơ Bản", level: "intermediate", q: "Literal types trong TypeScript là gì?", a: "Literal types là type chính xác là một giá trị cụ thể: `type Direction = 'left' | 'right' | 'up' | 'down'` — chỉ chấp nhận đúng 4 giá trị đó. Kết hợp với union tạo enum-like types mà không có runtime overhead của enum thật. Ví dụ thực tế: `type Status = 'loading' | 'success' | 'error'` cho API state. Bẫy: TypeScript suy luận `let dir = 'left'` là `string`, không phải literal — dùng `const` hoặc `as const` để giữ literal type. Là nền tảng của discriminated unions và type narrowing." },
  { id: 326, category: "TypeScript", subcategory: "Types Cơ Bản", level: "intermediate", q: "void khác undefined như thế nào trong TypeScript?", a: "void là return type của hàm không trả về giá trị có nghĩa. undefined là giá trị cụ thể. Function type (cb: () => void) cho phép cb trả về bất kỳ giá trị gì mà không dùng result. Function implementation () => undefined phải return undefined tường minh. void linh hoạt hơn cho callbacks." },
  { id: 327, category: "TypeScript", subcategory: "Types Cơ Bản", level: "intermediate", q: "Type narrowing là gì? Các cách narrow type trong TypeScript?", a: "Type narrowing là thu hẹp type trong code branch dựa trên kiểm tra. Cách narrow: typeof, instanceof, in operator, equality check, truthiness check, type predicates (is), assertion functions, discriminated unions. TypeScript tự động narrow trong if/else, switch, ternary." },
  { id: 328, category: "TypeScript", subcategory: "Types Cơ Bản", level: "beginner", q: "as keyword (type assertion) là gì? Khi nào dùng?", a: "Type assertion value as Type nói với TS 'trust me, tôi biết kiểu này'. Không kiểm tra runtime, chỉ compile time. Dùng khi TS không thể infer (DOM queries, JSON.parse). Tránh dùng để cast bừa bãi - sẽ mất type safety. as unknown as Type (double assertion) là dấu hiệu code có vấn đề." },
  { id: 329, category: "TypeScript", subcategory: "Types Cơ Bản", level: "intermediate", q: "Non-null assertion operator (!) là gì?", a: "! sau expression nói với TS rằng value không phải null/undefined: document.getElementById('id')!. Hữu ích khi biết chắc value tồn tại nhưng TS không thể prove. Tránh lạm dụng vì có thể gây runtime error. Tốt hơn là dùng optional chaining hoặc explicit null check." },
  { id: 330, category: "TypeScript", subcategory: "Types Cơ Bản", level: "beginner", q: "Tuple type trong TypeScript là gì?", a: "Tuple là array với số lượng và kiểu phần tử cố định: type Point = [number, number]. Phần tử có thể có tên: type Entry = [key: string, value: number]. Hỗ trợ optional (?) và rest elements. Thường dùng cho function return nhiều giá trị, CSV rows, React useState." },
  { id: 331, category: "TypeScript", subcategory: "Types Cơ Bản", level: "intermediate", q: "Enum trong TypeScript là gì? Numeric vs string enum khác nhau thế nào?", a: "Enum khai báo tập hợp named constants. Numeric enum: tự động assign 0,1,2... Có thể reverse lookup (Direction[0] = 'Up'). String enum: mỗi member phải assign string value tường minh, không có reverse lookup nhưng dễ debug hơn. Const enum: inlined tại compile time, không sinh runtime code." },
  { id: 332, category: "TypeScript", subcategory: "Types Cơ Bản", level: "intermediate", q: "satisfies operator trong TypeScript là gì?", a: "satisfies (TS 4.9) kiểm tra type mà không mở rộng type declaration. Khác as: satisfies vẫn infer type cụ thể nhất có thể và báo lỗi nếu không match. Ví dụ: const config = {...} satisfies Config - TS check config đúng Config nhưng giữ literal types của values." },
  { id: 333, category: "TypeScript", subcategory: "Types Cơ Bản", level: "advanced", q: "Declaration merging trong TypeScript là gì?", a: "Declaration merging cho phép nhiều declarations cùng tên merge lại. Interface merging: hai interface cùng tên tự động merge properties (open interface). Namespace merging: thêm properties vào namespace có sẵn. Module augmentation: thêm types vào modules bên ngoài (ví dụ extend Express Request). Chỉ interface mới merge, không phải type alias." },
  { id: 334, category: "TypeScript", subcategory: "Types Cơ Bản", level: "intermediate", q: "const assertion (as const) là gì?", a: "as const biến values thành readonly literal types cụ thể nhất. Array thành readonly tuple, object properties thành readonly literal types. Ví dụ: const dirs = ['left', 'right'] as const tạo type readonly ['left', 'right'] thay string[]. Hữu ích để tạo strongly-typed constants." },
  { id: 335, category: "TypeScript", subcategory: "Types Cơ Bản", level: "beginner", q: "TypeScript strict mode bao gồm những gì?", a: "strict: true bật nhiều checks: strictNullChecks (null/undefined không assign cho typed vars), strictFunctionTypes, strictPropertyInitialization, noImplicitAny, noImplicitThis, strictBindCallApply. Luôn bật strict: true cho dự án mới. Khi migrate JS sang TS có thể bật từng flag dần." },

  // === TypeScript: Interface & Type (336-345) ===
  { id: 336, category: "TypeScript", subcategory: "Interface & Type", level: "beginner", q: "interface và type alias khác nhau như thế nào? Khi nào dùng cái nào?", a: "Interface: có thể extend và merge (declaration merging), chỉ describe object shapes. Type alias: linh hoạt hơn (union, intersection, primitives, tuples, conditional types), không merge. Quy tắc: dùng interface cho public API và khi cần extend, dùng type cho unions/intersections và khi cần advanced type features." },
  { id: 337, category: "TypeScript", subcategory: "Interface & Type", level: "beginner", q: "Cách extend interface và type trong TypeScript?", a: "Interface: interface Child extends Parent { ... } và extends nhiều: extends A, B. Type: type Combined = A & B (intersection). Interface có thể extend type và ngược lại. Extends kiểm tra compatibility (không thể re-declare incompatible property), còn & intersection merge tất cả." },
  { id: 338, category: "TypeScript", subcategory: "Interface & Type", level: "intermediate", q: "Index signature trong TypeScript là gì?", a: "Index signature cho phép object có keys không biết trước: { [key: string]: value }. Tất cả explicit properties phải compatible với index signature type. string index signature làm tất cả properties phải match kiểu. Dùng Record<string, ValueType> thay thế khi cần, rõ ràng hơn." },
  { id: 339, category: "TypeScript", subcategory: "Interface & Type", level: "beginner", q: "Optional properties (?) và readonly properties là gì?", a: "Optional property (prop?: Type) có thể có hoặc không, type là Type | undefined khi access. readonly property không thể reassign sau khởi tạo (chỉ compile time, không phải runtime deep freeze). Readonly<T> làm tất cả properties readonly. readonly arrays: ReadonlyArray<T> hoặc readonly T[]." },
  { id: 340, category: "TypeScript", subcategory: "Interface & Type", level: "intermediate", q: "Discriminated unions là gì? Tại sao hữu ích?", a: "Discriminated union là union trong đó mỗi member có common literal property (discriminant): type Shape = {kind: 'circle', radius: number} | {kind: 'square', side: number}. TypeScript narrow type tự động khi check discriminant trong if/switch. Giúp type-safe handling cases khác nhau, thay cho if-else kiểm tra kiểu thủ công." },
  { id: 341, category: "TypeScript", subcategory: "Interface & Type", level: "intermediate", q: "Function type trong interface và type alias như thế nào?", a: "Interface: call signature {(arg: Type): ReturnType} hoặc method signature {method(arg: Type): ReturnType}. Type alias: type Fn = (arg: Type) => ReturnType. Overloads trong interface: khai báo nhiều call signatures. Function interfaces cũng có thể có properties (như jQuery $ function)." },
  { id: 342, category: "TypeScript", subcategory: "Interface & Type", level: "advanced", q: "Module augmentation là gì?", a: "Module augmentation cho phép thêm types vào module đã có: declare module 'express' { interface Request { user?: User } }. Dùng để extend third-party types mà không fork. Cần import module đó (ambient augmentation vs global augmentation). Rất hữu ích cho middleware patterns." },
  { id: 343, category: "TypeScript", subcategory: "Interface & Type", level: "intermediate", q: "Recursive types trong TypeScript là gì?", a: "TypeScript hỗ trợ recursive type aliases: type TreeNode = { value: number; children: TreeNode[] }. Hữu ích cho tree structures, nested JSON, linked lists. Type alias có thể tự tham chiếu. Interface luôn hỗ trợ recursive (vì là named type), type alias cũng hỗ trợ từ TS 3.7." },
  { id: 344, category: "TypeScript", subcategory: "Interface & Type", level: "advanced", q: "Branded types (nominal types) trong TypeScript là gì?", a: "TypeScript dùng structural typing (shape giống nhau là tương thích). Branded types tạo nominal typing: type UserId = string & {readonly _brand: 'UserId'}. Ngăn nhầm lẫn giữa các string types semantically khác nhau (UserId vs Email). Tạo via type assertion một lần qua factory function." },
  { id: 345, category: "TypeScript", subcategory: "Interface & Type", level: "intermediate", q: "Excess property checking trong TypeScript là gì?", a: "TypeScript kiểm tra extra properties khi assign object literal trực tiếp vào typed variable. Nếu type không có property đó, báo lỗi. Nhưng assign qua biến trung gian không bị check. Behavior này giúp phát hiện typos trong config objects. Workaround: index signature hoặc type assertion." },

  // === TypeScript: Generics (346-360) ===
  { id: 346, category: "TypeScript", subcategory: "Generics", level: "intermediate", q: "Generics trong TypeScript là gì? Tại sao cần thiết?", a: "Generics cho phép tạo components (functions, classes, interfaces) có thể hoạt động với nhiều kiểu dữ liệu mà vẫn type-safe. Thay dùng any, dùng type parameter <T>. Ví dụ: function identity<T>(arg: T): T trả về cùng kiểu nhận vào. Tái sử dụng code mà không mất type information." },
  { id: 347, category: "TypeScript", subcategory: "Generics", level: "intermediate", q: "Generic constraints (extends) trong TypeScript là gì?", a: "Constraints giới hạn type parameter phải extend một type cụ thể: function getProperty<T, K extends keyof T>(obj: T, key: K). Ngăn dùng với types không compatible. Có thể constrain multiple: T extends A & B. Constraints cho phép access properties trên type parameter." },
  { id: 348, category: "TypeScript", subcategory: "Generics", level: "intermediate", q: "keyof operator là gì?", a: "`keyof T` trả về union type của tất cả keys của T: `keyof {a: number, b: string}` cho ra `'a' | 'b'`. Dùng với generics để type-safe property access: `function get<T, K extends keyof T>(obj: T, key: K): T[K]` đảm bảo key tồn tại và return đúng kiểu. `keyof typeof obj` lấy keys của object value (không phải type). Hay gặp trong utility types như `Pick`, `Record`, và khi build form hay table components cần truy cập dynamic property một cách an toàn." },
  { id: 349, category: "TypeScript", subcategory: "Generics", level: "advanced", q: "Mapped types trong TypeScript là gì?", a: "Mapped types tạo type mới bằng cách biến đổi properties của type khác: { [K in keyof T]: ... }. Có thể thêm/xóa modifiers: +readonly, -readonly, +?, -?. Ví dụ: Readonly<T> = { readonly [K in keyof T]: T[K] }. Là nền tảng của nhiều built-in utility types." },
  { id: 350, category: "TypeScript", subcategory: "Generics", level: "advanced", q: "Conditional types trong TypeScript là gì?", a: "Conditional types: T extends U ? X : Y. Evaluate tại compile time dựa vào type relationship. Distributive với union types: khi T là union, distribute trên từng member. Dùng với infer để extract parts of types. Nền tảng của Exclude, Extract, NonNullable, ReturnType, và nhiều utility types." },
  { id: 351, category: "TypeScript", subcategory: "Generics", level: "advanced", q: "infer keyword trong conditional types là gì?", a: "infer khai báo type variable trong conditional type để 'capture' type được infer: type ReturnType<T> = T extends (...args: any) => infer R ? R : never. Chỉ dùng trong extends clause của conditional type. Cho phép extract nested types từ complex types." },
  { id: 352, category: "TypeScript", subcategory: "Generics", level: "intermediate", q: "Default type parameters là gì?", a: "Generic type parameters có thể có default: function create<T = string>(). Nếu không cung cấp type argument, dùng default. Hữu ích cho optional configuration, React components (T = {}), backward-compatible API changes. Default phải compatible với constraint nếu có." },
  { id: 353, category: "TypeScript", subcategory: "Generics", level: "advanced", q: "Variance trong TypeScript generics là gì?", a: "Variance mô tả how subtype relationships propagate qua generic types. Covariant (read-only): Array<Dog> compatible với Array<Animal>. Contravariant (write-only): function input types. Invariant: mutable containers. TypeScript dùng structural subtyping và có variance checking cho function types (in/out keywords từ TS 4.7)." },
  { id: 354, category: "TypeScript", subcategory: "Generics", level: "intermediate", q: "Generic classes trong TypeScript là gì?", a: "Class có thể generic: class Stack<T> { items: T[] = []; push(item: T) {...} pop(): T {...} }. Type parameter available trong toàn bộ class. Static members không thể dùng class type parameter. Khi instantiate: new Stack<number>() hoặc để TS infer từ constructor args." },
  { id: 355, category: "TypeScript", subcategory: "Generics", level: "advanced", q: "Template literal types trong TypeScript là gì?", a: "Template literal types tạo string types từ combinations: type Greeting = `Hello ${string}`. Kết hợp với union: type Direction = 'top' | 'bottom'; type Padding = `padding-${Direction}`. Cực kỳ mạnh cho type-safe event names, CSS properties, API endpoints. Intrinsic types: Uppercase, Lowercase, Capitalize, Uncapitalize." },
  { id: 356, category: "TypeScript", subcategory: "Generics", level: "advanced", q: "Recursive conditional types là gì?", a: "Recursive conditional types là kiểu điều kiện tự gọi lại chính nó, cho phép duyệt qua các nested types ở mọi cấp độ, ví dụ: type DeepPartial<T> = T extends object ? { [K in keyof T]?: DeepPartial<T[K]> } : T sẽ biến tất cả properties thành optional ở mọi tầng lồng nhau. TypeScript giới hạn độ sâu đệ quy (thường khoảng 50 levels) để tránh infinite loop trong quá trình type checking. Kỹ thuật này rất hữu ích để xây dựng các utility types phức tạp như DeepReadonly, DeepRequired, hay Flatten để biến đổi cấu trúc dữ liệu lồng nhau một cách type-safe." },
  { id: 357, category: "TypeScript", subcategory: "Generics", level: "intermediate", q: "Utility type Parameters<T> và ConstructorParameters<T> là gì?", a: "Parameters<T> là utility type trích xuất tuple chứa kiểu của tất cả tham số từ một function type T, ví dụ Parameters<typeof Math.max> cho ra [number, number]. ConstructorParameters<T> hoạt động tương tự nhưng dành cho constructor của class, trả về tuple các kiểu tham số khi khởi tạo đối tượng. Bên trong, cả hai đều sử dụng infer keyword trong conditional type: T extends (...args: infer P) => any ? P : never để suy luận ra kiểu tham số. Chúng đặc biệt hữu ích khi cần forward arguments sang hàm khác, tạo wrapper functions, hoặc xây dựng higher-order functions mà vẫn giữ nguyên type safety." },
  { id: 358, category: "TypeScript", subcategory: "Generics", level: "advanced", q: "Variadic tuple types là gì?", a: "Variadic tuples (TS 4.0) cho phép spread generic types trong tuples: type Concat<T extends unknown[], U extends unknown[]> = [...T, ...U]. Cải thiện typing cho rest parameters và tuple manipulation. Cho phép model patterns như function composition với typed args chính xác." },
  { id: 359, category: "TypeScript", subcategory: "Generics", level: "intermediate", q: "Generic functions với multiple type parameters như thế nào?", a: "Hàm có thể có nhiều type params: function zip<T, U>(arr1: T[], arr2: U[]): [T, U][]. Relationships giữa params được mô tả qua constraints và conditional types. Inference hoạt động independently cho mỗi param. Đặt tên rõ ràng (TKey, TValue) thay chỉ T, U, V khi có nhiều params." },
  { id: 360, category: "TypeScript", subcategory: "Generics", level: "advanced", q: "Higher-kinded types trong TypeScript có thể simulate như thế nào?", a: "TypeScript không có native HKTs nhưng có thể simulate qua type maps (interface URItoKind) và lookup: type Kind<F, A>. Thư viện fp-ts dùng pattern này. HKTs cho phép abstract over type constructors (Functor, Monad). Phức tạp nhưng cần thiết cho functional programming patterns mạnh." },

  // === TypeScript: Utility Types (361-375) ===
  { id: 361, category: "TypeScript", subcategory: "Utility Types", level: "beginner", q: "Partial<T> và Required<T> là gì?", a: "Partial<T> làm tất cả properties của T thành optional. Required<T> làm tất cả optional thành required. Hữu ích: Partial cho update payloads (không cần gửi toàn bộ object), Required để enforce tất cả fields có giá trị sau validation. Chỉ shallow: không ảnh hưởng nested types." },
  { id: 362, category: "TypeScript", subcategory: "Utility Types", level: "beginner", q: "Record<K, V> là gì? Khác index signature như thế nào?", a: "Record<Keys, Value> tạo object type với specific keys và value type: Record<string, number>. Khác index signature: Keys phải là specific union hoặc string/number/symbol. Record<'a' | 'b', number> yêu cầu cả 'a' lẫn 'b' phải có (không optional). Rõ ràng hơn và type-safe hơn index signature." },
  { id: 363, category: "TypeScript", subcategory: "Utility Types", level: "beginner", q: "Pick<T, K> và Omit<T, K> là gì?", a: "Pick<T, K> tạo type chỉ với subset of properties K từ T: `Pick<User, 'id' | 'name'>` chỉ giữ lại id và name. Omit<T, K> là ngược lại: tạo type với tất cả properties trừ K, ví dụ `Omit<User, 'password'>` để không lộ mật khẩu trong response. Hữu ích cho DTOs, API response shaping, và form state management khi chỉ cần một phần của type. Mẹo: dùng Omit khi cần loại ít field, Pick khi cần giữ ít field — chọn cái nào viết ngắn hơn." },
  { id: 364, category: "TypeScript", subcategory: "Utility Types", level: "intermediate", q: "Exclude<T, U> và Extract<T, U> là gì?", a: "`Exclude<T, U>` loại bỏ khỏi union T những types có thể assign cho U: `Exclude<'a'|'b'|'c', 'a'>` cho ra `'b'|'c'`. `Extract<T, U>` ngược lại — giữ lại những types assign được cho U: `Extract<string|number|boolean, string|number>` cho ra `string|number`. Ví dụ thực tế: `type NonString<T> = Exclude<T, string>` để lọc string ra khỏi union. Mẹo nhớ: Exclude = loại ra (exclude từ vocabulary), Extract = trích ra phần giao nhau. Nền tảng của NonNullable<T> chính là `Exclude<T, null | undefined>`." },
  { id: 365, category: "TypeScript", subcategory: "Utility Types", level: "intermediate", q: "ReturnType<T> và Awaited<T> là gì?", a: "`ReturnType<T>` lấy return type của function T mà không cần khai báo lại: `type Result = ReturnType<typeof fetchUser>` tự động theo dõi khi hàm thay đổi. `Awaited<T>` unwrap Promise đệ quy: `Awaited<Promise<string>>` cho ra `string`, `Awaited<Promise<Promise<number>>>` cho ra `number`. Kết hợp cả hai cho async functions: `type Data = Awaited<ReturnType<typeof fetchData>>`. Rất hữu ích trong large codebases để tránh type duplication và đảm bảo types luôn đồng bộ với implementation." },
  { id: 366, category: "TypeScript", subcategory: "Utility Types", level: "intermediate", q: "NonNullable<T> là gì?", a: "`NonNullable<T>` loại bỏ `null` và `undefined` khỏi type T: `NonNullable<string | null | undefined>` cho ra `string`. Tương đương với `Exclude<T, null | undefined>`. Hay dùng sau khi đã kiểm tra null ở runtime nhưng TypeScript vẫn chưa tự narrow được — ví dụ kết quả từ `Array.find()` có type `T | undefined`, sau khi guard check có thể cast về `NonNullable`. Với strictNullChecks bật, đây là utility cần thiết để làm việc với optional values an toàn." },
  { id: 367, category: "TypeScript", subcategory: "Utility Types", level: "intermediate", q: "Readonly<T> và ReadonlyArray<T> là gì?", a: "Readonly<T> làm tất cả properties của T thành readonly (shallow). ReadonlyArray<T> là array không thể modify (push, pop, sort không available). Dùng với as const, Redux state, functional programming. Deep readonly cần custom type: DeepReadonly<T> với recursive mapped type." },
  { id: 368, category: "TypeScript", subcategory: "Utility Types", level: "advanced", q: "InstanceType<T> và ThisParameterType<T> là gì?", a: "InstanceType<T> lấy type của instance khi dùng new T(): InstanceType<typeof MyClass> = MyClass. Hữu ích với factory patterns và generic class handling. ThisParameterType<T> lấy type của this parameter trong function, OmitThisParameter<T> loại bỏ nó." },
  { id: 369, category: "TypeScript", subcategory: "Utility Types", level: "intermediate", q: "Hãy implement Partial<T> từ đầu để hiểu cách hoạt động.", a: "type MyPartial<T> = { [K in keyof T]?: T[K] }. Dùng mapped type iterate qua tất cả keys của T, thêm ? để optional. Tương tự: type MyRequired<T> = { [K in keyof T]-?: T[K] } (dấu - xóa optional modifier). Hiểu cách này giúp tạo custom utility types." },
  { id: 370, category: "TypeScript", subcategory: "Utility Types", level: "advanced", q: "Mutable<T> (ngược của Readonly) tạo như thế nào?", a: "TypeScript không có built-in Mutable nhưng có thể tạo: type Mutable<T> = { -readonly [K in keyof T]: T[K] }. Dấu - trước readonly xóa readonly modifier. Hữu ích khi cần temporarily mutate readonly objects (trong test setup chẳng hạn). Cũng có thể combine: type WritablePick<T, K extends keyof T>." },
  { id: 371, category: "TypeScript", subcategory: "Utility Types", level: "intermediate", q: "const enum và regular enum khác nhau về runtime như thế nào?", a: "Regular enum compile thành JS object (có runtime overhead, hỗ trợ reverse lookup). Const enum inline tất cả values tại compile time (không sinh runtime code, không có reverse lookup). Const enum không dùng được với declaration files và isolatedModules. Prefer string literal unions thay enum trong nhiều trường hợp." },
  { id: 372, category: "TypeScript", subcategory: "Utility Types", level: "advanced", q: "Deep partial và deep readonly type tạo như thế nào?", a: "DeepPartial được tạo bằng recursive conditional type: nếu T là object thì áp dụng optional modifier cho mỗi key và đệ quy vào giá trị con, ngược lại trả về T nguyên bản (type DeepPartial<T> = T extends object ? { [K in keyof T]?: DeepPartial<T[K]> } : T). DeepReadonly cần xử lý riêng trường hợp array bằng cách kiểm tra T extends (infer U)[] trước để chuyển thành ReadonlyArray<DeepReadonly<U>>, sau đó mới xử lý object bằng cách thêm readonly modifier cho tất cả keys và đệ quy tiếp. Việc tách riêng logic cho array là bắt buộc vì array có semantics khác với object thông thường, nếu không sẽ mất đi các array methods và tính đúng đắn của kiểu dữ liệu." },
  { id: 373, category: "TypeScript", subcategory: "Utility Types", level: "intermediate", q: "Parameters và ReturnType kết hợp như thế nào để tạo hàm wrapper?", a: "Dùng Parameters<T> và ReturnType<T> để type hàm wrapper giữ nguyên signature: function wrapper<T extends (...args: any) => any>(fn: T, ...args: Parameters<T>): ReturnType<T>. Hoặc dùng spread trong tuple: (...args: Parameters<T>) để forward args chính xác." },
  { id: 374, category: "TypeScript", subcategory: "Utility Types", level: "advanced", q: "Template literal utility types (Uppercase, Lowercase, Capitalize, Uncapitalize) là gì?", a: "Bốn intrinsic string manipulation types: Uppercase<S> chuyển toàn bộ thành hoa, Lowercase về thường, Capitalize chữ đầu thành hoa, Uncapitalize ngược lại. Dùng để tạo type-safe string transformations: type EventHandler<T extends string> = `on${Capitalize<T>}`." },
  { id: 375, category: "TypeScript", subcategory: "Utility Types", level: "intermediate", q: "ThisType<T> utility type là gì?", a: "ThisType<T> chỉ có effect khi --noImplicitThis bật. Dùng trong object literal để set context type của this bên trong methods. Không ảnh hưởng kết quả type, chỉ affect type của this trong scope đó. Dùng bởi Vue 2 options API để type this trong component options." },

  // === TypeScript: Advanced (376-400) ===
  { id: 376, category: "TypeScript", subcategory: "Advanced", level: "intermediate", q: "Type guards là gì? Các loại type guards trong TypeScript?", a: "Type guards thu hẹp type trong code branch. Loại: 1) typeof ('string', 'number'...), 2) instanceof (class instances), 3) in operator (property check), 4) equality (==, ===), 5) user-defined (function với return type is Type), 6) assertion functions (asserts condition). User-defined guards rất mạnh để custom narrowing." },
  { id: 377, category: "TypeScript", subcategory: "Advanced", level: "intermediate", q: "User-defined type guards (type predicates) là gì?", a: "Function type với return type 'param is Type': function isString(val: unknown): val is string { return typeof val === 'string' }. Khi function return true, TS narrow type của param. Nguy hiểm: TS tin type predicate hoàn toàn, implementation sai sẽ gây runtime bug mà không có compile error." },
  { id: 378, category: "TypeScript", subcategory: "Advanced", level: "advanced", q: "Decorators trong TypeScript là gì?", a: "Decorators là function đặc biệt apply lên class/method/property/accessor/parameter để modify behavior. Dùng @decorator syntax. TS 5.0+ hỗ trợ TC39 Stage 3 decorators natively (không cần flag). Legacy decorators (Angular, NestJS) vẫn dùng experimentalDecorators: true — hai loại không tương thích. Decorator factories: @Log() trả về decorator function." },
  { id: 379, category: "TypeScript", subcategory: "Advanced", level: "advanced", q: "Decorator metadata và reflect-metadata là gì?", a: "Reflect Metadata API cho phép đọc/ghi metadata trên class/method tại runtime. TypeScript emit metadata khi emitDecoratorMetadata: true (design:type, design:paramtypes, design:returntype). Dùng bởi dependency injection frameworks (Angular, NestJS) để resolve constructor params tự động." },
  { id: 380, category: "TypeScript", subcategory: "Advanced", level: "advanced", q: "Function overloads trong TypeScript là gì?", a: "Function overloads khai báo nhiều function signatures trước implementation: ít nhất 2 overload signatures + 1 implementation signature. Implementation phải compatible với tất cả overloads. Dùng khi function return type hoặc parameters khác nhau tùy input types. Giúp caller có type info chính xác cho mỗi usage." },
  { id: 381, category: "TypeScript", subcategory: "Advanced", level: "intermediate", q: "Declaration files (.d.ts) là gì?", a: "Declaration files chứa type declarations không có implementation (ambient declarations). Dùng để type third-party libraries không viết bằng TS. @types/ packages trên npm. Tự viết .d.ts khi cần declare types cho JS code hoặc global variables. declare module, declare global để augment types." },
  { id: 382, category: "TypeScript", subcategory: "Advanced", level: "intermediate", q: "tsconfig.json các options quan trọng nhất là gì?", a: "Trong tsconfig.json, strict: true là option quan trọng nhất vì nó bật toàn bộ strict type-checking bao gồm strictNullChecks, noImplicitAny và strictFunctionTypes. target xác định phiên bản ES output (ví dụ ES2020), module chọn hệ thống module (ESNext, CommonJS), và moduleResolution quyết định cách TypeScript tìm kiếm file khi import (node, bundler). Ngoài ra, paths cho phép cấu hình path aliases (ví dụ @/components), isolatedModules bắt buộc khi dùng bundlers như Vite hoặc esbuild vì chúng compile từng file riêng lẻ, và sourceMap: true giúp debug bằng cách map code đã compile về source TypeScript gốc." },
  { id: 383, category: "TypeScript", subcategory: "Advanced", level: "advanced", q: "Conditional types với distributive behavior là gì? Cách disable?", a: "Distributive conditional types xảy ra khi type parameter T đứng trơn (naked) trong điều kiện extends: TypeScript sẽ tự động tách union ra và áp dụng điều kiện cho từng thành phần, ví dụ (A | B) extends U ? X : Y sẽ thành (A extends U ? X : Y) | (B extends U ? X : Y). Hành vi này thường gây kết quả bất ngờ, ví dụ type IsNever<T> = T extends never ? true : false sẽ trả về never thay vì true khi T = never vì union rỗng không có phần tử nào để distribute. Để disable distributive behavior, ta wrap type parameter trong tuple: [T] extends [U] ? X : Y, lúc này TypeScript sẽ so sánh toàn bộ union như một khối thay vì phân tách từng thành phần." },
  { id: 384, category: "TypeScript", subcategory: "Advanced", level: "advanced", q: "TypeScript với React: generics trong components là gì?", a: "Generic components: function List<T>({items}: {items: T[]}) - nhưng trong .tsx cần disambiguate: <T,>({items}) hoặc <T extends unknown>. Generic components cần với tables, select components, form fields. React.FC<Props> vs function declaration - prefer function declaration cho flexibility." },
  { id: 385, category: "TypeScript", subcategory: "Advanced", level: "intermediate", q: "TypeScript với React: typing hooks như thế nào?", a: "useState: useState<Type>(init) khi init không đủ thông tin. useRef: useRef<HTMLElement>(null) cho DOM refs, useRef<T>(initialValue) cho mutable values. useReducer: type actions với discriminated unions. Custom hooks: return type thường được infer, nhưng có thể explicit để stable API." },
  { id: 386, category: "TypeScript", subcategory: "Advanced", level: "intermediate", q: "TypeScript với React: typing events là gì?", a: "React.ChangeEvent<HTMLInputElement> cho onChange, React.MouseEvent<HTMLButtonElement> cho onClick, React.FormEvent<HTMLFormElement> cho onSubmit. Nếu không nhớ chính xác: event.target, hover lên event trong IDE, hoặc dùng React.SyntheticEvent rộng hơn. event.target as HTMLInputElement để access value." },
  { id: 387, category: "TypeScript", subcategory: "Advanced", level: "advanced", q: "Assertion functions trong TypeScript là gì?", a: "Assertion functions type với 'asserts condition' hoặc 'asserts param is Type'. Khi function return (không throw), TS assume assertion đúng và narrow type. Dùng cho validation functions, invariant checks: function assert(cond: unknown): asserts cond { if (!cond) throw new Error() }." },
  { id: 388, category: "TypeScript", subcategory: "Advanced", level: "advanced", q: "NoInfer<T> utility type là gì?", a: "NoInfer<T> (TS 5.4) ngăn TypeScript infer type từ một argument cụ thể, forcing inference từ các arguments khác. Giải quyết vấn đề khi có multiple inference sites conflict. Ví dụ: hàm với default value - không muốn default value ảnh hưởng inference của type parameter chính." },
  { id: 389, category: "TypeScript", subcategory: "Advanced", level: "advanced", q: "Tại sao TypeScript dùng structural typing thay nominal typing?", a: "Structural typing (duck typing) kiểm tra shape/structure thay tên type. Hai types tương thích nếu có cùng properties. Phù hợp hơn với JavaScript (dynamic, object literal heavy). Nominal typing cần kiểm tra theo tên class/type. TypeScript kết hợp: structural làm mặc định + branded types cho nominal khi cần." },
  { id: 390, category: "TypeScript", subcategory: "Advanced", level: "advanced", q: "Type compatibility và assignability trong TypeScript hoạt động như thế nào?", a: "A assignable cho B nếu A có tất cả (và có thể nhiều hơn) properties của B. Subtype có thể assign cho supertype. Function parameters: contravariant (param type của subtype phải rộng hơn hoặc bằng). Return type: covariant (return type của subtype phải hẹp hơn hoặc bằng). strictFunctionTypes enforce contravariance." },
  { id: 391, category: "TypeScript", subcategory: "Advanced", level: "advanced", q: "const type parameters (TS 5.0) là gì?", a: "const type parameters: function identity<const T>(val: T): T. Giúp infer literal types mà không cần as const. Trước đây cần as const để get literal types, giờ generics tự infer. Hữu ích cho config objects, routing definitions, và bất kỳ nơi nào muốn preserve literal types." },
  { id: 392, category: "TypeScript", subcategory: "Advanced", level: "advanced", q: "Discriminated unions vs class hierarchy khi nào dùng cái nào?", a: "Discriminated unions: prefer khi data-centric, cần exhaustive matching, serializable (Redux actions, API responses). Class hierarchy: khi cần behavior với data, encapsulation, OOP patterns. Functional code thường prefer discriminated unions vì pattern matching dễ hơn. TypeScript exhausiveness checking qua never type." },
  { id: 393, category: "TypeScript", subcategory: "Advanced", level: "advanced", q: "Exhaustiveness checking trong TypeScript là gì?", a: "Sau khi handle tất cả cases trong discriminated union, assign default case sang variable type never: const exhaustive: never = value. Nếu có case chưa handle, TS báo lỗi vì giá trị đó không assign được cho never. Pattern này đảm bảo thêm case mới vào union sẽ bị catch ngay tại compile time." },
  { id: 394, category: "TypeScript", subcategory: "Advanced", level: "advanced", q: "using declarations và Symbol.dispose (TS 5.2) là gì?", a: "using declaration là tính năng từ đề xuất TC39 Explicit Resource Management, được TypeScript 5.2 hỗ trợ, cho phép tự động giải phóng tài nguyên khi biến ra khỏi scope mà không cần viết try/finally thủ công, ví dụ: using file = openFile() sẽ tự gọi cleanup khi kết thúc block. Object được gán cho using phải implement method [Symbol.dispose]() để TypeScript biết cách giải phóng, còn với tài nguyên bất đồng bộ thì dùng await using kết hợp với [Symbol.asyncDispose](). Tính năng này đặc biệt hữu ích cho việc quản lý file handles, database connections, và event listeners vì đảm bảo tài nguyên luôn được dọn dẹp đúng cách ngay cả khi có exception xảy ra." },
  { id: 395, category: "TypeScript", subcategory: "Advanced", level: "intermediate", q: "Path aliases trong TypeScript (paths config) là gì?", a: "paths trong tsconfig.json map import paths: '@components/*': ['src/components/*']. Giúp import ngắn hơn thay relative paths dài. Cần configure cả bundler (Vite, Webpack) vì TS compiler chỉ handle types, không transform imports. Dùng @ prefix là convention phổ biến." },
  { id: 396, category: "TypeScript", subcategory: "Advanced", level: "advanced", q: "Isolated modules và tại sao Vite/esbuild yêu cầu nó?", a: "isolatedModules: true yêu cầu mỗi file có thể compile standalone (không cần cross-file type information). Vite/esbuild strip types từng file riêng (nhanh hơn) thay full type checking. Hạn chế: không dùng const enum, namespace, và phải export type tường minh (import type). TS vẫn type check đầy đủ khi build." },
  { id: 397, category: "TypeScript", subcategory: "Advanced", level: "advanced", q: "TypeScript project references là gì?", a: "Project references trong tsconfig cho phép chia large codebase thành nhiều TS projects có thể build independently và incrementally. Mỗi project có tsconfig với references. tsc --build (hoặc -b) xây dựng theo dependency order. Cải thiện build time và IDE performance cho monorepos." },
  { id: 398, category: "TypeScript", subcategory: "Advanced", level: "advanced", q: "Type-only imports và exports là gì?", a: "Type-only imports (import type { Foo } from './foo') chỉ import thông tin kiểu dữ liệu và bị xóa hoàn toàn khỏi code JavaScript sau khi compile, không tạo ra bất kỳ runtime import nào. Điều này đặc biệt quan trọng khi bật isolatedModules (bắt buộc với Vite, esbuild) vì các bundler này compile từng file riêng lẻ và không thể biết một import là type hay value. Tương tự, export type { Foo } dùng để re-export chỉ type information, giúp ngăn circular dependency issues vì không tạo side effects ở runtime. Từ TypeScript 5.0+, ta có thể mix type và value imports trong cùng một statement: import { type Foo, bar } from './module', trong đó chỉ bar được giữ lại sau compile." },
  { id: 399, category: "TypeScript", subcategory: "Advanced", level: "advanced", q: "Ambient declarations là gì?", a: "Ambient declarations (declare keyword) nói với TS về types tồn tại ở runtime nhưng không qua import: declare const jQuery: any. declare module, declare namespace, declare global để mô tả global APIs, third-party libs, hay augment existing types. .d.ts files chứa toàn bộ ambient declarations." },
  { id: 400, category: "TypeScript", subcategory: "Advanced", level: "advanced", q: "TypeScript performance: tại sao type checking có thể chậm và cách cải thiện?", a: "Type checking chậm do: complex conditional types, deep recursion, large union types, excessive use of infer. Cải thiện: bật incremental compilation, dùng project references, skipLibCheck: true, tránh deeply recursive types, prefer interface over type cho object shapes (merge tốt hơn), dùng tsc --diagnostics để profile." },
]
